def is_octagonal(n):
    """
    Check if n is an octagonal number.
    """
    if n < 0:
        return False
    a = 1
    b = 1
    while True:
        if a * (a + 1) * (2 * a + 1) == 2 * n:
            return True
        a += 1
        b += 1

def octagonal(n):
    """
    Calculate the nth octagonal number.
    """
    a = 1
    b = 1
    while True:
        if a * (a + 1) * (2 * a + 1) == 2 * n:
            return a * (a + 1) * (2 * a + 1)
        a += 1
        b += 1

