def eulerian_num(n, m):
    """
    Find the Eulerian number a(n, m).
    """
    if n < 0 or m < 0:
        return 0
    elif n == 0:
        return 1
    elif m == 0:
        return 1
    elif m == n:
        return 1
    else:
        return eulerian_num(n-1, m-1) + eulerian_num(n-1, m) + eulerian_num(n-1, m-1)

