def find_solution(a, b, n):
    if a == 0 and b == 0:
        return None
    if a == 0:
        return (n // b, 1)
    if b == 0:
        return (1, n // a)
    if n % a == 0:
        return (n // a, 0)
    if n % b == 0:
        return (0, n // b)
    gcd = find_gcd(a, b)
    if n % gcd != 0:
        return None
    return (n // gcd, 0) + find_solution(a // gcd, b // gcd, n // gcd)

