def max_sum(arr):
    max_sum = 0
    for i in range(len(arr)):
        left_sum = 0
        right_sum = 0
        for j in range(i):
            if arr[j] < arr[i]:
                left_sum += arr[j]
        for j in range(i+1, len(arr)):
            if arr[j] > arr[i]:
                right_sum += arr[j]
        max_sum = max(max_sum, left_sum + right_sum)
    return max_sum

