def max_sum_increasing_subseq(arr, i, k, j):
    if i == len(arr):
        return 0
    if k > i:
        return max_sum_increasing_subseq(arr, i + 1, k, j)
    if j == len(arr):
        return max(max_sum_increasing_subseq(arr, i, k, j + 1), max_sum_increasing_subseq(arr, i, k, j + 1) + arr[j])
